### What to Do

Create a comprehensive end-to-end test script that simulates exactly how Claude Code (and other AI agents) interact with dcg in hook mode.

### Why This Is Critical

AI agents interact with dcg via a very specific contract:
1. Agent sends command to dcg on stdin
2. dcg evaluates and returns JSON verdict on stdout
3. Agent parses JSON and decides whether to execute
4. Human sees rich output on stderr

If ANY part of this contract breaks, agents fail silently or crash.

### Test Script Structure

```bash
#!/bin/bash
# tests/e2e/agent_workflow_test.sh
set -euo pipefail

# Logging with timestamps
log() {
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] $*" >&2
}

log "Starting E2E agent workflow test"

# Build dcg with rich-output
log "Building dcg with rich-output feature..."
cargo build --features rich-output --release
DCG="./target/release/dcg"

# Test 1: Allowed command returns valid JSON with allow verdict
log "Test 1: Allowed command (echo hello)"
RESULT=$(echo "echo hello" | $DCG --hook-mode 2>/dev/null)
log "Raw result: $RESULT"

if ! echo "$RESULT" | jq -e '.verdict == "allow"' > /dev/null; then
    log "FAIL: Expected 'allow' verdict for safe command"
    exit 1
fi
log "PASS: Allowed command returned correct verdict"

# Test 2: Denied command returns valid JSON with deny verdict
log "Test 2: Denied command (rm -rf /)"
RESULT=$(echo "rm -rf /" | $DCG --hook-mode 2>/dev/null)
log "Raw result: $RESULT"

if ! echo "$RESULT" | jq -e '.verdict == "deny"' > /dev/null; then
    log "FAIL: Expected 'deny' verdict for dangerous command"
    exit 1
fi

# Verify JSON has required fields
for field in verdict reason pack pattern; do
    if ! echo "$RESULT" | jq -e ".$field" > /dev/null; then
        log "FAIL: Missing required field '$field' in deny response"
        exit 1
    fi
done
log "PASS: Denied command returned correct verdict with all fields"

# Test 3: stderr has human-readable output, stdout is pure JSON
log "Test 3: Stream separation (stdout=JSON, stderr=human)"
STDOUT=$(echo "rm -rf /" | $DCG --hook-mode 2>/dev/null)
STDERR=$(echo "rm -rf /" | $DCG --hook-mode 2>&1 >/dev/null)

# stdout must be valid JSON
if ! echo "$STDOUT" | jq . > /dev/null 2>&1; then
    log "FAIL: stdout is not valid JSON"
    log "stdout content: $STDOUT"
    exit 1
fi

# stdout must NOT contain ANSI codes
if echo "$STDOUT" | grep -q $'\x1b\['; then
    log "FAIL: stdout contains ANSI escape codes"
    exit 1
fi
log "PASS: Stream separation verified"

# Test 4: Performance check (must complete in <50ms)
log "Test 4: Performance (<50ms latency)"
START=$(date +%s%N)
echo "echo test" | $DCG --hook-mode > /dev/null 2>&1
END=$(date +%s%N)
LATENCY_MS=$(( (END - START) / 1000000 ))
log "Latency: ${LATENCY_MS}ms"

if [ "$LATENCY_MS" -gt 100 ]; then
    log "FAIL: Latency ${LATENCY_MS}ms exceeds 100ms threshold"
    exit 1
fi
log "PASS: Performance within acceptable range"

# Test 5: NO_COLOR environment respected
log "Test 5: NO_COLOR environment"
STDERR_COLOR=$(echo "rm -rf /" | $DCG --hook-mode 2>&1 >/dev/null)
STDERR_NO_COLOR=$(NO_COLOR=1 echo "rm -rf /" | $DCG --hook-mode 2>&1 >/dev/null)

if echo "$STDERR_NO_COLOR" | grep -q $'\x1b\['; then
    log "FAIL: stderr contains ANSI codes when NO_COLOR=1"
    exit 1
fi
log "PASS: NO_COLOR environment respected"

# Test 6: DCG_NO_RICH environment forces legacy output
log "Test 6: DCG_NO_RICH environment"
DCG_NO_RICH=1 echo "rm -rf /" | $DCG --hook-mode > /dev/null 2>&1
if [ $? -ne 0 ]; then
    log "FAIL: DCG_NO_RICH=1 caused error"
    exit 1
fi
log "PASS: DCG_NO_RICH environment works"

log "=========================================="
log "ALL E2E TESTS PASSED"
log "=========================================="
```

